                    "input.source_type": str(
                        (run_started.get("input_source") or {}).get("source_type")
                    ),
                    "input.path": str((run_started.get("input_source") or {}).get("path")),
                    "input.has_prompt": run_started.get("prompt") not in (None, ""),
                    **version_attributes,
